func outputRobotStatus(session *robot.Session, h *handoff.Handoff, path string, usage map[string]float64) error {
    output := map[string]interface{}{
        "sessions": session,
    }

    if h != nil {
        output["handoff"] = map[string]interface{}{
            "session":     h.Session,
            "goal":        h.Goal,
            "now":         h.Now,
            "path":        path,
            "age_seconds": int(time.Since(h.CreatedAt).Seconds()),
            "status":      h.Status,
        }
    }

    if len(usage) > 0 {
        output["context"] = usage
    }

    // Generate alerts
    var alerts []map[string]interface{}
    for paneID, pct := range usage {
        if pct >= 70 {
            alerts = append(alerts, map[string]interface{}{
                "type":  "context_warning",
                "agent": paneID,
                "usage": pct,
            })
        }
    }
    if len(alerts) > 0 {
        output["alerts"] = alerts
    }

    return outputJSON(output)
}
