func TestAuditLogger_Write(t *testing.T) {
    tmpDir := t.TempDir()
    logPath := filepath.Join(tmpDir, "audit.log")

    logger, err := audit.NewLogger(audit.Config{
        Path:     logPath,
        MaxSize:  1024 * 1024, // 1MB
        Compress: false,
    })
    require.NoError(t, err)
    defer logger.Close()

    entry := audit.NewEntry(audit.EventAgentSpawned)
    err = logger.Write(entry)
    require.NoError(t, err)

    // Verify written
    data, err := os.ReadFile(logPath)
    require.NoError(t, err)
    require.Contains(t, string(data), entry.ID)

    t.Logf("Log contents: %s", data)
}

func TestAuditLogger_Rotation(t *testing.T) {
    tmpDir := t.TempDir()
    logPath := filepath.Join(tmpDir, "audit.log")

    logger, err := audit.NewLogger(audit.Config{
        Path:       logPath,
        MaxSize:    100, // Very small for testing
        MaxBackups: 3,
    })
    require.NoError(t, err)
    defer logger.Close()

    // Write enough to trigger rotation
    for i := 0; i < 50; i++ {
        entry := audit.NewEntry(audit.EventAgentSpawned,
            audit.WithMetadata(map[string]interface{}{
                "iteration": i,
                "padding":   strings.Repeat("x", 10),
            }),
        )
        logger.Write(entry)
    }

    // Should have rotated files
    files, _ := filepath.Glob(filepath.Join(tmpDir, "audit.log*"))
    assert.Greater(t, len(files), 1, "Should have rotated")

    t.Logf("Log files after rotation: %v", files)
}

func TestAuditLogger_Concurrent(t *testing.T) {
    tmpDir := t.TempDir()
    logPath := filepath.Join(tmpDir, "audit.log")

    logger, err := audit.NewLogger(audit.Config{Path: logPath})
    require.NoError(t, err)
    defer logger.Close()

    var wg sync.WaitGroup
    errors := make(chan error, 100)

    for i := 0; i < 100; i++ {
        wg.Add(1)
        go func(n int) {
            defer wg.Done()
            entry := audit.NewEntry(audit.EventAgentSpawned,
                audit.WithMetadata(map[string]interface{}{"n": n}),
            )
            if err := logger.Write(entry); err != nil {
                errors <- err
            }
        }(i)
    }

    wg.Wait()
    close(errors)

    for err := range errors {
        t.Errorf("Concurrent write error: %v", err)
    }

    // Verify all entries written
    data, _ := os.ReadFile(logPath)
    lines := strings.Split(strings.TrimSpace(string(data)), "\n")
    assert.Equal(t, 100, len(lines))
}
```

