func TestAuditIntegrity_Hash(t *testing.T) {
    entry := audit.Entry{
        ID:        "test_1",
        Event:     audit.EventAgentSpawned,
        Timestamp: time.Date(2025, 1, 15, 10, 0, 0, 0, time.UTC),
    }

    hash := audit.ComputeHash(entry)
    assert.NotEmpty(t, hash)

    // Deterministic
    assert.Equal(t, hash, audit.ComputeHash(entry))

    // Changes with data
    entry2 := entry
    entry2.ID = "test_2"
    assert.NotEqual(t, hash, audit.ComputeHash(entry2))
}

func TestAuditIntegrity_ChainVerification(t *testing.T) {
    store := audit.NewMemoryStore()

    // Add chained entries
    for i := 0; i < 5; i++ {
        store.AddWithChain(audit.NewEntry(audit.EventAgentSpawned))
    }

    // Verify chain
    valid, err := store.VerifyChain()
    require.NoError(t, err)
    assert.True(t, valid)

    // Tamper and verify fails
    store.Entries[2].Actor = "tampered"
    valid, err = store.VerifyChain()
    assert.False(t, valid)
    assert.ErrorContains(t, err, "chain broken at entry 2")
}
