+			version := getTmuxVersion(tt.binaryPath)
+
+			if tt.wantEmpty && version != "" {
+				t.Errorf("getTmuxVersion(%q) = %q, want empty", tt.binaryPath, version)
+			}
+			if !tt.wantEmpty && version == "" {
+				// Skip if tmux isn't installed
